#include <bits/stdc++.h>
using namespace std;

int n;
long long t[300005];

int lowbit(int x) {
    return x & (-x);
}

void add(int p, int x) {
    while (p <= n) {
        t[p] += x;
        p += lowbit(p);
    }
}

long long sum(int p) {
    long long s = 0;
    while (p) {
        s += t[p];
        p -= lowbit(p);
    }
    return s;
}

int main() {
    cin >> n;
    long long ans = 0;
    for (int i = 1; i <= n; i++) {
        int a;
        cin >> a;
        ans += sum(a);
        add(a + 1, 1);
    }
    cout << ans;
    return 0;
}
